from flask import Flask, request, Response
from prometheus_client import generate_latest, Counter, Gauge, Histogram, make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware
import time
import random

app = Flask(__name__)

# 1. Define Prometheus Metrics
# Counter for total requests
REQUESTS_TOTAL = Counter(
    'flask_http_requests_total',
    'Total number of HTTP requests.',
    ['method', 'endpoint', 'status']
)

# Histogram for request duration
REQUEST_DURATION_SECONDS = Histogram(
    'flask_http_request_duration_seconds',
    'HTTP request duration in seconds.',
    ['method', 'endpoint']
)

# Gauge for currently active requests
IN_PROGRESS_REQUESTS = Gauge(
    'flask_http_requests_in_progress',
    'Number of HTTP requests currently in progress.',
    ['method', 'endpoint']
)

# Business Metric: Counter for processed items
PROCESSED_ITEMS_TOTAL = Counter(
    'app_processed_items_total',
    'Total number of business items processed.',
    ['item_type']
)

# Business Metric: Gauge for current stock level
STOCK_LEVEL = Gauge(
    'app_stock_level',
    'Current stock level of a specific product.',
    ['product_id']
)

# Business Metric: Histogram for processing time of an item
ITEM_PROCESSING_TIME_SECONDS = Histogram(
    'app_item_processing_time_seconds',
    'Time taken to process a business item in seconds.',
    ['item_type']
)

# 2. Middleware for request instrumentation
@app.before_request
def before_request_hook():
    request.start_time = time.time()
    IN_PROGRESS_REQUESTS.labels(request.method, request.path).inc()

@app.after_request
def after_request_hook(response):
    request_duration = time.time() - request.start_time
    method = request.method
    endpoint = request.path
    status = response.status_code

    REQUESTS_TOTAL.labels(method, endpoint, status).inc()
    REQUEST_DURATION_SECONDS.labels(method, endpoint).observe(request_duration)
    IN_PROGRESS_REQUESTS.labels(method, endpoint).dec()

    return response

# 3. Application Routes
@app.route('/')
def hello_world():
    # Simulate some work
    time.sleep(random.uniform(0.01, 0.1))
    return 'Hello, World!'

@app.route('/process/<item_type>')
def process_item(item_type):
    start_time = time.time()
    # Simulate processing an item
    processing_time = random.uniform(0.05, 0.5)
    time.sleep(processing_time)

    PROCESSED_ITEMS_TOTAL.labels(item_type).inc()
    ITEM_PROCESSING_TIME_SECONDS.labels(item_type).observe(processing_time)

    # Simulate stock level changes
    current_stock = STOCK_LEVEL.labels(product_id='product_A').get()
    if current_stock is None:
        current_stock = 100  # Initial stock
    STOCK_LEVEL.labels(product_id='product_A').set(current_stock - random.randint(1, 5))

    return f'Processed {item_type} in {processing_time:.2f} seconds!'

@app.route('/slow')
def slow_endpoint():
    time.sleep(random.uniform(0.5, 2.0))
    return 'This was a slow response!'

# 4. Prometheus Metrics Endpoint
@app.route('/metrics')
def metrics():
    return Response(generate_latest(), mimetype='text/plain')

